import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { profileAPI, mentorsAPI } from '../../services/api';
import './Progress.css';

const Progress = () => {
  const [progress, setProgress] = useState({
    quizCompleted: 0,
    profileCompleted: 0,
    skillsAdded: 0,
    mentorsConnected: 0,
    coursesEnrolled: 0
  });
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    fetchProgress();
  }, [user]);

  const fetchProgress = async () => {
    setLoading(true);
    try {
      console.log('🔄 Fetching progress data...');
      
      // Get fresh user data from profile API
      const profileResponse = await profileAPI.getProfile();
      console.log('📊 Profile API response:', profileResponse);
      
      let userData = user; // Start with current user data
      
      if (profileResponse && profileResponse.user) {
        userData = profileResponse.user;
        console.log('✅ Using fresh user data from API');
      } else {
        console.log('⚠️ Using cached user data from AuthContext');
      }

      // Get mentor requests to count connections
      let mentorRequestsCount = 0;
      try {
        const mentorResponse = await mentorsAPI.getMyRequests();
        console.log('👥 Mentor requests:', mentorResponse);
        if (mentorResponse && mentorResponse.requests) {
          mentorRequestsCount = mentorResponse.requests.filter(
            req => req.status === 'accepted'
          ).length;
        }
      } catch (mentorError) {
        console.log('No mentor requests data available');
      }

      const quizCount = userData.quizResults?.length || 0;
      const profile = userData.profile || {};
      const skillsCount = profile.skills?.length || 0;
      
      console.log('📈 Progress data:', {
        quizCount,
        profile,
        skillsCount,
        mentorRequestsCount
      });

      const progressData = {
        quizCompleted: quizCount > 0 ? 100 : 0,
        profileCompleted: calculateProfileCompletion(profile),
        skillsAdded: Math.min((skillsCount / 5) * 100, 100),
        mentorsConnected: Math.min((mentorRequestsCount / 3) * 100, 100),
        coursesEnrolled: 0 // You can add course enrollment later
      };
      
      console.log('🎯 Calculated progress:', progressData);
      setProgress(progressData);
      
    } catch (error) {
      console.error('❌ Error fetching progress:', error);
      // Use fallback data from current user
      const fallbackProgress = calculateProgressFromUser(user);
      setProgress(fallbackProgress);
    } finally {
      setLoading(false);
    }
  };

  const calculateProgressFromUser = (userData) => {
    const quizCount = userData?.quizResults?.length || 0;
    const profile = userData?.profile || {};
    const skillsCount = profile.skills?.length || 0;
    
    return {
      quizCompleted: quizCount > 0 ? 100 : 0,
      profileCompleted: calculateProfileCompletion(profile),
      skillsAdded: Math.min((skillsCount / 5) * 100, 100),
      mentorsConnected: 0,
      coursesEnrolled: 0
    };
  };

  const calculateProfileCompletion = (profile) => {
    if (!profile) return 0;
    
    let completed = 0;
    let total = 5; // bio, education, experience, skills, interests

    if (profile.bio && profile.bio.trim().length > 0) {
      completed++;
      console.log('✅ Bio completed');
    }

    if (profile.education && profile.education.trim().length > 0) {
      completed++;
      console.log('✅ Education completed');
    }

    if (profile.experience !== undefined && profile.experience !== null) {
      completed++;
      console.log('✅ Experience completed');
    }

    if (profile.skills && profile.skills.length > 0) {
      completed++;
      console.log('✅ Skills completed');
    }

    if (profile.interests && profile.interests.length > 0) {
      completed++;
      console.log('✅ Interests completed');
    }

    const percentage = Math.round((completed / total) * 100);
    console.log(`📊 Profile completion: ${completed}/${total} = ${percentage}%`);
    return percentage;
  };

  const getOverallProgress = () => {
    const values = Object.values(progress);
    const overall = Math.round(values.reduce((a, b) => a + b, 0) / values.length);
    console.log('🎯 Overall progress:', overall);
    return overall;
  };

  const getProgressColor = (percentage) => {
    if (percentage >= 80) return '#10b981'; // Green
    if (percentage >= 50) return '#f59e0b'; // Yellow
    return '#ef4444'; // Red
  };

  const refreshProgress = () => {
    console.log('🔄 Manually refreshing progress...');
    fetchProgress();
  };

  if (!user) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your progress.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading your progress...
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="progress-container">
      <div className="container">
        <div className="progress-header">
          <h1>📊 Your Progress</h1>
          <p>Track your career development journey</p>
          <button 
            onClick={refreshProgress}
            className="btn btn-secondary refresh-btn"
          >
            🔄 Refresh Progress
          </button>
        </div>

        {/* Debug Info - Remove in production */}
        <div className="debug-info" style={{display: 'none'}}>
          <p><strong>User Data:</strong> {JSON.stringify(user, null, 2)}</p>
        </div>

        {/* Overall Progress */}
        <div className="overall-progress">
          <div className="progress-card">
            <h2>Overall Completion</h2>
            <div className="progress-circle">
              <div 
                className="circle" 
                style={{ 
                  background: `conic-gradient(${getProgressColor(getOverallProgress())} ${getOverallProgress() * 3.6}deg, #e2e8f0 0deg)` 
                }}
              >
                <span className="progress-value">{getOverallProgress()}%</span>
              </div>
            </div>
            <p>Complete all sections to maximize your career guidance</p>
          </div>
        </div>

        {/* Detailed Progress */}
        <div className="detailed-progress">
          <div className="progress-item">
            <div className="progress-info">
              <h3>Career Assessment</h3>
              <span className="progress-percentage">{progress.quizCompleted}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.quizCompleted}%`,
                  backgroundColor: getProgressColor(progress.quizCompleted)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.quizCompleted === 100 
                ? '✅ Quiz completed! Check your results.' 
                : 'Take the career quiz to discover your ideal career path.'
              }
            </p>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Profile Completion</h3>
              <span className="progress-percentage">{progress.profileCompleted}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.profileCompleted}%`,
                  backgroundColor: getProgressColor(progress.profileCompleted)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.profileCompleted === 100 
                ? '✅ Profile fully completed!' 
                : 'Complete your profile for personalized recommendations.'
              }
            </p>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Skills Development</h3>
              <span className="progress-percentage">{progress.skillsAdded}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.skillsAdded}%`,
                  backgroundColor: getProgressColor(progress.skillsAdded)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.skillsAdded >= 80 
                ? '✅ Great job building your skills!' 
                : 'Add more skills to your profile to get better career matches.'
              }
            </p>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Mentor Connections</h3>
              <span className="progress-percentage">{progress.mentorsConnected}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.mentorsConnected}%`,
                  backgroundColor: getProgressColor(progress.mentorsConnected)
                }}
              ></div>
            </div>
            <p className="progress-description">
              {progress.mentorsConnected > 0 
                ? `✅ Connected with mentors!` 
                : 'Connect with mentors to accelerate your career growth.'
              }
            </p>
          </div>

          <div className="progress-item">
            <div className="progress-info">
              <h3>Learning Progress</h3>
              <span className="progress-percentage">{progress.coursesEnrolled}%</span>
            </div>
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ 
                  width: `${progress.coursesEnrolled}%`,
                  backgroundColor: getProgressColor(progress.coursesEnrolled)
                }}
              ></div>
            </div>
            <p className="progress-description">
              Enroll in courses to develop skills for your target career.
            </p>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="progress-actions">
          <h3>Next Steps</h3>
          <div className="action-buttons">
            {progress.quizCompleted === 0 && (
              <button 
                onClick={() => window.location.href = '/quiz'}
                className="btn btn-primary"
              >
                Start Career Quiz
              </button>
            )}
            {progress.profileCompleted < 100 && (
              <button 
                onClick={() => window.location.href = '/profile'}
                className="btn btn-secondary"
              >
                Complete Profile
              </button>
            )}
            {progress.skillsAdded < 80 && (
              <button 
                onClick={() => window.location.href = '/profile'}
                className="btn btn-secondary"
              >
                Add More Skills
              </button>
            )}
            <button 
              onClick={() => window.location.href = '/mentors'}
              className="btn btn-primary"
            >
              Connect with Mentors
            </button>
            <button 
              onClick={() => window.location.href = '/courses'}
              className="btn btn-secondary"
            >
              Explore Courses
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Progress;
